## Current Issues & Recommendations

### 1. Missing Body Parsing Middleware
The app has no `express.json()` or `express.urlencoded()` middleware. Any POST/PUT routes added later would silently fail to parse request bodies.

### 2. No Input Validation on Query Parameters
The `/users` route accepts query parameters (e.g., for filtering) without any validation or sanitization. This is an open invitation for injection or unexpected behavior.

### 3. No Rate Limiting
There is no rate limiting, making the API vulnerable to brute-force and DoS attacks.

### 4. No Centralized Error Handler
Unhandled errors will leak stack traces to clients in some Express configurations.

### 5. No Helmet (Security Headers)
Missing HTTP security headers (e.g., `X-Content-Type-Options`, `X-Frame-Options`, `Content-Security-Policy`).

### 6. Missing 404 Handler
Unmatched routes return Express's default HTML response, which leaks framework information.

### 7. Hardcoded Static Data Exposed Without Auth
The `/users` route returns PII (names + emails) with no authentication or authorization check.

---

## Improved Version

```js
'use strict';

const express = require('express');
const helmet  = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// ── Security headers ────────────────────────────────────────────────────────
app.use(helmet());

// ── Body parsing (safe size cap to prevent payload-flooding) ────────────────
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// ── Rate limiting ───────────────────────────────────────────────────────────
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// ── Routes ──────────────────────────────────────────────────────────────────
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Example: validate an optional `?id=` query param
    const { id } = req.query;
    if (id !== undefined) {
      const parsed = Number(id);
      if (!Number.isInteger(parsed) || parsed < 1) {
        return res.status(400).json({ error: 'Invalid id: must be a positive integer.' });
      }
    }

    // NOTE: replace with a real DB query — never interpolate raw query params
    //       directly into SQL/NoSQL queries.
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob',   email: 'bob@example.com'   },
    ];

    const result = id ? users.filter(u => u.id === Number(id)) : users;
    res.json(result);
  } catch (err) {
    next(err); // pass to centralized error handler
  }
});

// ── 404 handler ─────────────────────────────────────────────────────────────
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// ── Centralized error handler ────────────────────────────────────────────────
// Must have exactly 4 params so Express recognises it as an error handler.
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log internally — never expose raw err.message to clients in production
  console.error('[error]', err);
  const statusCode = err.status ?? err.statusCode ?? 500;
  res.status(statusCode).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error.'
      : err.message,
  });
});

// ── Start ────────────────────────────────────────────────────────────────────
const PORT = Number(process.env.PORT) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

